import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch13: CareerQuestion[] = [
  { id: "ota-2203", stem: "An OTA is treating a client with a Bennett's fracture of the thumb. After immobilization, what is the focus of rehabilitation?", options: ["Only passive ROM", "Restore thumb CMC joint mobility, grip and pinch strength, and functional use of the thumb for opposition and prehension activities", "Immobilize indefinitely", "Only wrist exercises"], correctIndex: 1, rationale: "Bennett's fracture (1st metacarpal base intra-articular fracture): post-immobilization rehab focuses on restoring thumb CMC joint ROM, opposition, grip/pinch strength, scar management, and functional hand use.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2204", stem: "A client with multiple sclerosis has an intention tremor that interferes with feeding. Which adaptation is MOST helpful?", options: ["Lighter utensils", "Weighted utensils and wrist weights to dampen the tremor during fine motor tasks like feeding", "Faster eating", "No adaptations available"], correctIndex: 1, rationale: "MS intention tremor: weighted utensils/wrist weights add mass to the limb, dampening oscillations. Additional strategies: stabilize proximal joints, use two hands, scoop dish/plate guard, non-slip mat, and covered cup with straw.", difficulty: 2, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2205", stem: "An OTA is working with a child who demonstrates W-sitting. Why should this be discouraged?", options: ["It is a normal sitting position", "W-sitting promotes internal rotation of hips, limits trunk rotation, may contribute to orthopedic problems, and does not encourage core strengthening", "It strengthens the core", "It improves flexibility"], correctIndex: 1, rationale: "W-sitting: promotes hip IR, limits trunk rotation and weight shifting, may contribute to hip/knee problems, reduces core activation, and limits cross-midline reaching. Encourage ring sitting, tailor sitting, or long sitting instead.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2206", stem: "A client with Dupuytren's contracture has progressive MCP flexion contracture of the ring finger. What conservative treatment does the OTA provide?", options: ["Aggressive stretching", "Static progressive or dynamic extension splinting, gentle stretching, and functional activities to maintain hand opening", "Only surgical referral", "No treatment available"], correctIndex: 1, rationale: "Dupuytren's contracture conservative management: extension splinting (static progressive or dynamic), gentle stretching, functional activities maintaining extension, and client education. Splinting may slow progression but surgery may be needed for severe cases.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2207", stem: "An OTA observes a client performing a stand-pivot transfer. The client loses balance during the pivot. What should the OTA modify?", options: ["Have the client transfer faster", "Ensure the client wears non-slip footwear, surfaces are close together, the client pauses before pivoting, and uses proper hand placement for support", "Remove all assistive devices", "Skip transfer training"], correctIndex: 1, rationale: "Stand-pivot transfer balance issues: check footwear (non-slip), reduce distance between surfaces, ensure surfaces are at equal height, teach pausing before pivot, proper hand placement, and consider transfer board if unresolved.", difficulty: 1, category: "Patient Safety", topic: "ADL Training" },
  { id: "ota-2208", stem: "A client with a total elbow replacement has which postoperative precautions?", options: ["No precautions", "Avoid lifting more than 5 pounds with the affected arm and avoid forceful forearm rotation for the first 6-12 weeks", "Full weight-bearing immediately", "Only avoid overhead reaching"], correctIndex: 1, rationale: "Total elbow arthroplasty precautions: permanent lifting restriction (typically 5-10 lbs), avoid repetitive forceful activities, protect the ulnar nerve, controlled ROM progression per surgeon protocol, and avoid valgus stress.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2209", stem: "An OTA is treating a client with a peripheral vestibular disorder. Which intervention helps with gaze stabilization?", options: ["Eye patching", "VOR (vestibulo-ocular reflex) exercises — fixating on a target while moving the head to improve visual stability during head movement", "Dark room therapy", "Only medication"], correctIndex: 1, rationale: "VOR exercises (gaze stabilization): fixate on a stationary target while moving head horizontally/vertically (VORx1). Progress to moving target with head movement in opposite direction (VORx2). Improves visual stability during functional head movements.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2210", stem: "A client with a recent amputation reports phantom limb pain. Which OT intervention addresses this?", options: ["Ignore the pain", "Mirror therapy, desensitization of the residual limb, mental imagery, and graded motor imagery to reduce phantom pain", "Only medication", "Remove the prosthesis"], correctIndex: 1, rationale: "Phantom limb pain interventions: mirror therapy (visual feedback of intact limb creates illusion of affected limb), graded motor imagery (left/right recognition, imagined movements, mirror therapy), desensitization, TENS, and relaxation.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2211", stem: "An OTA is treating a child with developmental delays who cannot stack 2 blocks. At what developmental age does block stacking of 2 blocks typically emerge?", options: ["6 months", "14-15 months — stacking 2 blocks is a fine motor milestone indicating developing release control and visual-motor integration", "3 years", "6 years"], correctIndex: 1, rationale: "Block stacking milestones: 2 blocks at 14-15 months, 3-4 blocks at 18 months, 6 blocks at 2 years, 8-10 blocks at 3 years. Block stacking requires voluntary release, visual-motor integration, and postural stability.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2212", stem: "A client with a humeral shaft fracture has a radial nerve palsy. Which functional deficit is expected?", options: ["Loss of elbow flexion", "Wrist drop, finger drop, and loss of thumb extension due to radial nerve injury affecting the extensor compartment", "Loss of finger flexion", "Loss of forearm pronation"], correctIndex: 1, rationale: "Radial nerve palsy from humeral shaft fracture: loss of wrist extension (wrist drop), finger MCP extension (finger drop), thumb extension/abduction. Grip is weakened due to lack of wrist extension stabilization.", difficulty: 2, category: "Anatomy & Physiology", topic: "Hand Therapy" },
  { id: "ota-2213", stem: "An OTA is providing cognitive rehabilitation using the multicontextual approach. What is the key principle?", options: ["Practice only in one setting", "Practice strategies across multiple contexts and environments to promote generalization and transfer of cognitive skills", "Only computer-based exercises", "Avoid real-world application"], correctIndex: 1, rationale: "Multicontextual approach (Toglia): practice cognitive strategies across varied tasks, contexts, and environments to promote transfer and generalization. Self-monitoring training, strategy instruction, and graded environmental complexity.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2214", stem: "A client with systemic lupus erythematosus (SLE) has joint pain and fatigue. What OT principle is essential?", options: ["Push through fatigue", "Balance rest and activity, use joint protection principles, energy conservation, and modify activities during disease flares", "Only rest during flares", "Avoid all physical activity"], correctIndex: 1, rationale: "SLE OT management: balance rest/activity, joint protection during flares, energy conservation, stress management, sun protection education, adaptive equipment, and pacing. Monitor for fatigue exacerbation and modify activities accordingly.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2215", stem: "An OTA is using neurodevelopmental treatment (NDT/Bobath) with a stroke client. What is the primary focus?", options: ["Strengthen spastic muscles", "Facilitate normal movement patterns, inhibit abnormal tone, and promote postural control through handling and task-oriented activities", "Only passive stretching", "Only compensatory techniques"], correctIndex: 1, rationale: "NDT/Bobath: facilitate normal movement patterns through skilled handling, inhibit abnormal muscle tone, promote postural control, and integrate these into functional activities. Current NDT incorporates task-specific practice.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2216", stem: "A client with end-stage renal disease is on dialysis. What scheduling consideration should the OTA address?", options: ["Schedule therapy during dialysis", "Schedule therapy on non-dialysis days when the client has more energy and avoid the affected arm used for the dialysis access site", "No scheduling considerations", "Schedule therapy immediately after dialysis"], correctIndex: 1, rationale: "Dialysis scheduling: therapy on non-dialysis days (fatigue common post-dialysis), avoid BP/blood draws on access arm, protect fistula/graft site during activities, monitor for fluid overload symptoms, and watch for fatigue.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2217", stem: "An OTA is assessing a client's fine motor dexterity. Which standardized assessment uses pegs to measure manual dexterity?", options: ["Grip dynamometry", "Nine-Hole Peg Test or Purdue Pegboard — timed peg placement tests that measure fine motor speed and dexterity", "Goniometry", "Manual muscle testing"], correctIndex: 1, rationale: "Fine motor dexterity assessments: Nine-Hole Peg Test (timed, unilateral), Purdue Pegboard (unilateral, bilateral, assembly), Jebsen-Taylor Hand Function Test (functional tasks), and Minnesota Rate of Manipulation Test.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2218", stem: "A client with a high thoracic SCI (T2) is at risk for autonomic dysreflexia. Which common trigger should the OTA be aware of during ADL training?", options: ["Room temperature", "Full bladder, constipation, tight clothing, or skin irritation below the level of injury", "Loud noises", "Emotional stress only"], correctIndex: 1, rationale: "Autonomic dysreflexia triggers: full bladder (most common), constipation, tight clothing/shoes, skin irritation (ingrown toenail, pressure sore), temperature extremes, and urinary tract infection. OTA must monitor during ADLs for these triggers.", difficulty: 2, category: "Patient Safety", topic: "Neurological Rehab" },
  { id: "ota-2219", stem: "An OTA is adapting a computer workstation for a client with a cervical SCI. Which ergonomic principle is essential?", options: ["Monitor below eye level", "Position monitor at eye level, support forearms, use adaptive input devices (trackball, voice recognition, mouth stick), and ensure wheelchair positioning allows neutral posture", "Standard keyboard only", "No modifications needed"], correctIndex: 1, rationale: "SCI computer workstation: monitor at eye level, arm supports, adaptive input (voice recognition, head mouse, mouth stick, switch access), wheelchair positioning for neutral posture, and proper desk height for wheelchair.", difficulty: 2, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2220", stem: "A client with a hip fracture is learning to navigate stairs with a cane. What is the correct sequence for ascending?", options: ["Cane first, then affected leg", "Unaffected leg up first, then affected leg and cane together — 'up with the good' mnemonic", "Affected leg up first", "Both legs simultaneously"], correctIndex: 1, rationale: "Stair climbing with cane: ascending — good leg up first (bearing weight on cane and affected leg), then affected leg and cane together. Descending — cane and affected leg first, then good leg down. Mnemonic: 'up with the good, down with the bad.'", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2221", stem: "An OTA is treating a client with complex hand injuries involving multiple structures. Which assessment should be performed first?", options: ["Grip strength testing", "Wound assessment and edema measurement before assessing ROM, sensation, and function to establish baseline and identify precautions", "Fine motor dexterity testing", "Return-to-work evaluation"], correctIndex: 1, rationale: "Complex hand injury initial assessment priority: wound status, edema, then AROM/PROM (within surgeon guidelines), sensation, and function. Wound and edema assessment identify precautions before more demanding testing.", difficulty: 2, category: "Clinical Scenarios", topic: "Hand Therapy" },
  { id: "ota-2222", stem: "A client with dementia demonstrates sundowning behavior. What environmental modification helps?", options: ["Increase stimulation in the evening", "Increase lighting in late afternoon, establish calming evening routines, reduce noise and stimulation, and maintain consistent daily schedules", "Keep the client awake during the day", "Only medication management"], correctIndex: 1, rationale: "Sundowning management: increase light in late afternoon (reduces disorientation), calming evening routine, reduce stimulation, consistent schedule, address hunger/thirst/toileting needs, and minimize caffeine and daytime sleeping.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2223", stem: "An OTA is treating a client with a distal biceps tendon repair. What movement is restricted in the early postoperative phase?", options: ["Shoulder flexion", "Active elbow extension and forearm pronation against resistance to protect the repaired tendon insertion", "Wrist flexion", "Finger motion"], correctIndex: 1, rationale: "Distal biceps repair precautions: avoid active elbow extension and resisted forearm pronation (these stress the repaired tendon). Typically protected in a splint at 90° elbow flexion, forearm supination for 4-6 weeks.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2224", stem: "A client with obsessive-compulsive disorder has rituals that take 4 hours daily. Which OT approach is therapeutic?", options: ["Allow unlimited ritual time", "Exposure and response prevention (ERP) through graded functional activities, establishing structured routines, and developing alternative coping strategies", "Only discuss the rituals", "Avoid triggering situations entirely"], correctIndex: 1, rationale: "OCD OT intervention: ERP through functional activities (graded exposure to triggers without performing rituals), structured daily routines that limit ritual time, alternative coping strategies, and meaningful occupation engagement.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2225", stem: "An OTA is teaching energy conservation to a client with chronic fatigue syndrome. Which principle is MOST important?", options: ["Complete all tasks at once", "Prioritize tasks, delegate non-essential activities, use pacing strategies, and plan rest periods before fatigue becomes overwhelming", "Push through fatigue", "Avoid all activity"], correctIndex: 1, rationale: "CFS energy conservation: prioritize essential tasks, delegate, pace activities (alternate heavy/light), plan rest periods (before exhaustion), modify task methods, use adaptive equipment, and maintain activity diary to identify patterns.", difficulty: 1, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2226", stem: "A client with a hip disarticulation prosthesis is learning to don the device. What is the correct sequence?", options: ["Start with the socket", "Apply the socket/interface first, then align the prosthetic components, and ensure proper suspension before weight-bearing and gait training", "Start with the foot component", "No specific sequence"], correctIndex: 1, rationale: "Hip disarticulation prosthesis donning: position socket around pelvis/residual limb, ensure proper fit and suspension, check alignment, and progress to weight-bearing. OTA assists with donning technique, skin inspection, and functional mobility.", difficulty: 4, category: "Clinical Case Scenarios", topic: "Assistive Devices" },
  { id: "ota-2227", stem: "An OTA is providing intervention for a client with body dysmorphic disorder. What therapeutic approach is appropriate?", options: ["Agree with body distortions", "Cognitive-behavioral techniques to challenge distorted body perceptions, graded social participation, and engagement in meaningful occupations to shift focus from appearance", "Only cosmetic recommendations", "Avoid discussing body image"], correctIndex: 1, rationale: "BDD OT intervention: CBT for distorted body perception, graded exposure to social situations, reduction of mirror-checking/camouflaging behaviors, engagement in meaningful occupations, and building self-worth beyond appearance.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2228", stem: "A client with a cervical SCI at C3 requires which type of respiratory support?", options: ["No respiratory support", "Mechanical ventilation — C3 SCI is above the diaphragm innervation (C3-C5), resulting in inability to breathe independently", "Only supplemental oxygen", "Incentive spirometry only"], correctIndex: 1, rationale: "C3 SCI: above diaphragm innervation (phrenic nerve C3-C5, primarily C4). Client is ventilator-dependent. May eventually wean if some C4-C5 function returns. Diaphragmatic pacing may be an option for some clients.", difficulty: 2, category: "Anatomy & Physiology", topic: "Neurological Rehab" },
  { id: "ota-2229", stem: "An OTA is providing intervention for a child with Erb's palsy. Which therapeutic activity promotes shoulder external rotation?", options: ["Internal rotation stretching only", "Reaching activities with the arm in a position of external rotation, such as reaching for toys placed at shoulder height and to the side", "Only passive internal rotation", "No intervention for Erb's palsy"], correctIndex: 1, rationale: "Erb's palsy (C5-C6) rehab: promote shoulder ER/abduction and elbow flexion through functional reaching, play activities in ER position, stretching to prevent contractures, and strengthening as nerve recovery occurs.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2230", stem: "A client with a pressure injury classified as Stage 3 has which tissue involvement?", options: ["Superficial epidermal loss only", "Full-thickness skin loss with visible subcutaneous fat but no exposed bone, tendon, or muscle", "Intact skin with non-blanchable redness", "Exposed bone or muscle"], correctIndex: 1, rationale: "Stage 3 pressure injury: full-thickness skin loss. Subcutaneous fat may be visible. Bone, tendon, and muscle are NOT exposed. Depth varies by anatomical location. May include undermining and tunneling.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2231", stem: "An OTA is treating a client with a scaphoid fracture that has healed. What functional concern should be addressed?", options: ["Only grip strength", "Wrist ROM (especially extension and radial deviation), thumb opposition, grip/pinch strength, and return to functional activities with wrist stability", "Only finger motion", "Only shoulder range"], correctIndex: 1, rationale: "Post-scaphoid fracture rehab: restore wrist ROM (especially extension, radial deviation), thumb mobility, grip/pinch strength, and functional wrist stability. Monitor for avascular necrosis (poor blood supply to proximal pole).", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2232", stem: "A client with bipolar disorder is in a manic episode. Which OT intervention is appropriate?", options: ["Complex multi-step projects", "Structured, repetitive gross motor activities that channel excess energy, with minimal stimulation and clear boundaries", "Group discussion about feelings", "Unstructured creative activities"], correctIndex: 1, rationale: "Manic episode OT: structured gross motor activities (channel energy), minimize stimulation, clear boundaries, short tasks (limited attention span), safe environment, consistent routine, and avoid competitive/stimulating activities.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2233", stem: "An OTA is treating a client with a proximal humerus fracture. After immobilization, which exercise progression is appropriate?", options: ["Immediate heavy resistance", "Pendulum exercises progressing to PROM, then AROM, then gentle resistance as bone healing and pain allow", "No exercise for 3 months", "Only shoulder shrugs"], correctIndex: 1, rationale: "Proximal humerus fracture rehab progression: pendulum exercises (early), PROM (gentle), AAROM, AROM, gentle resistive exercises. Timeline depends on fracture type, fixation method, and radiographic evidence of healing.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2234", stem: "A client with diabetes has a non-healing foot ulcer. What role does the OTA play in wound management?", options: ["Perform sharp debridement", "Assess for contributing factors (footwear, foot care knowledge), provide patient education on foot care, blood glucose management, and appropriate footwear", "Only apply wound dressings", "No role for OTA"], correctIndex: 1, rationale: "OTA diabetic foot ulcer role: assess contributing factors, educate on foot care (daily inspection, proper footwear, nail care), blood glucose management, footwear assessment/recommendations, activity modification, and coordinate with wound care team.", difficulty: 2, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2235", stem: "An OTA is conducting a kitchen safety assessment for a client with cognitive impairment. Which hazard is of GREATEST concern?", options: ["Cluttered countertops", "Unattended stove use due to impaired memory and judgment creating fire risk", "Open shelving", "Multiple appliances"], correctIndex: 1, rationale: "Kitchen safety with cognitive impairment: unattended stove is highest fire risk. Interventions: automatic stove shut-off, microwave instead of stove, remove knobs, supervision during cooking, and simple meal preparation tasks.", difficulty: 1, category: "Patient Safety", topic: "Cognitive Rehab" },
  { id: "ota-2236", stem: "A client with Huntington's disease has chorea. Which activity adaptation is helpful for feeding?", options: ["Use regular utensils", "Use weighted utensils, non-slip mat, plate guard, covered cup, and stabilize the arm proximally to reduce involuntary movement impact", "Feed the client exclusively", "No adaptations available"], correctIndex: 1, rationale: "Huntington's chorea feeding adaptations: weighted utensils, non-slip mat, plate guard, covered cup with lid, arm stabilization, adapted handles, swivel utensils, and seated positioning with trunk support to reduce chorea during meals.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Assistive Devices" },
  { id: "ota-2237", stem: "An OTA is using the Occupational Therapy Practice Framework (OTPF). Which step comes after evaluation?", options: ["Discharge", "Intervention planning — developing goals and selecting intervention approaches based on evaluation findings", "Re-evaluation only", "Documentation only"], correctIndex: 1, rationale: "OTPF process: evaluation (occupational profile + analysis of occupational performance) → intervention (plan, implementation, review) → outcomes (measuring results). Intervention planning follows evaluation and guides treatment.", difficulty: 1, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2238", stem: "A client with a posterior interosseous nerve syndrome has difficulty extending the fingers at the MCPs but can extend the wrist. What explains this?", options: ["Combined nerve injury", "The posterior interosseous nerve innervates finger extensors (EDC) but not ECRL (wrist extension), which is innervated by radial nerve proper before the PIN branch", "Tendon rupture", "Joint stiffness"], correctIndex: 1, rationale: "Posterior interosseous nerve: motor branch of radial nerve. Innervates EDC, ECU, EIP, EDM, APL, EPB, EPL. ECRL innervated by radial nerve before PIN branch, so wrist extension is preserved but finger/thumb extension is lost.", difficulty: 5, category: "Anatomy & Physiology", topic: "Hand Therapy" },
  { id: "ota-2239", stem: "An OTA is treating a client with a burn on the dorsal hand. Which anti-deformity splinting position is correct?", options: ["Wrist flexion, MCP extension", "Wrist 20-30° extension, MCPs 70-80° flexion, IPs in extension, thumb abducted — to counteract the expected deformity from scar contracture", "Full fist position", "Wrist neutral, all fingers extended"], correctIndex: 1, rationale: "Dorsal hand burn anti-deformity position: wrist extension 20-30°, MCP flexion 70-80° (stretches collateral ligaments), IP extension, thumb palmar abduction. This opposes the typical claw deformity of MCP hyperextension and IP flexion from scar contracture.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2240", stem: "A client with a traumatic amputation of the index finger is having difficulty with key pinch. What compensatory technique should the OTA teach?", options: ["Use only the ring finger", "Modify pinch pattern to use the middle finger and thumb for lateral pinch activities previously performed by the index finger", "Avoid all pinch activities", "Only gross grasp activities"], correctIndex: 1, rationale: "Index finger amputation compensatory pinch: substitute middle finger for lateral (key) pinch, tripod pinch with middle-ring-thumb, and modified tip pinch. Practice functional tasks (keys, coins, writing) with the adapted pinch patterns.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Hand Therapy" },
  { id: "ota-2241", stem: "An OTA is providing relaxation training for a client with PTSD. Which technique may be contraindicated?", options: ["Deep breathing", "Progressive muscle relaxation may increase body awareness and trigger hyperarousal or flashbacks in some trauma survivors", "Guided imagery with safe place", "Grounding techniques"], correctIndex: 1, rationale: "PMR with PTSD: may increase body awareness and trigger hyperarousal, flashbacks, or dissociation. Some trauma survivors experience increased anxiety with body-focused relaxation. Use grounding or guided imagery (safe place) as alternatives initially.", difficulty: 4, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2242", stem: "A child with developmental coordination disorder (DCD) has difficulty with scissors skills. At what age should a child be able to cut on a line?", options: ["2 years", "4-5 years — by this age, children should be able to cut on a straight line and begin cutting simple shapes", "7 years", "10 years"], correctIndex: 1, rationale: "Scissors development: holds scissors at 2 years, snips at 2.5, cuts across paper at 3, cuts on line at 4, cuts circle at 4.5, cuts square at 5, cuts complex shapes at 6. Cutting requires bilateral coordination, visual-motor integration, and hand strength.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2243", stem: "An OTA is treating a client with lateral medullary syndrome (Wallenberg syndrome). Which deficit is characteristic?", options: ["Upper extremity paralysis", "Dysphagia, ipsilateral facial numbness, contralateral body numbness, ataxia, and vertigo from posterior inferior cerebellar artery occlusion", "Bilateral leg weakness", "Expressive aphasia"], correctIndex: 1, rationale: "Wallenberg syndrome (lateral medullary infarct): dysphagia, hoarseness, ipsilateral facial pain/numbness, contralateral body pain/temperature loss, ipsilateral ataxia, vertigo, nystagmus, and Horner's syndrome. No motor paralysis.", difficulty: 5, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2244", stem: "A client with an ankle-foot orthosis (AFO) is being seen in OT. What should the OTA assess regarding upper extremity function?", options: ["Nothing related to the AFO", "Assess how the AFO affects transfers, lower body dressing independence, and the need for upper extremity assistive devices for balance", "Only assess the ankle", "Only assess walking speed"], correctIndex: 1, rationale: "OT assessment with AFO: impact on transfers (sit-to-stand, floor-to-stand), lower body dressing (donning/doffing shoes over AFO), bathing (shower entry/exit), and need for UE assistive devices for balance during ADLs.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2245", stem: "An OTA is providing therapy to a client with a liver transplant. What precaution is essential?", options: ["No precautions", "Follow immunosuppression precautions — strict hand hygiene, avoid sick contacts, monitor for signs of infection, and report temperature elevations", "Only monitor liver enzymes", "Avoid all physical activity"], correctIndex: 1, rationale: "Post-transplant precautions: immunosuppression increases infection risk. Strict hand hygiene, avoid sick contacts, monitor for infection signs (fever, redness, drainage), report temperature >100.4°F, and coordinate with transplant team.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2246", stem: "A client with a spinal cord injury uses a sliding board for transfers. What technique ensures safe transfer?", options: ["Lean away from the board", "Position the board under the buttocks angled toward the target surface, lean forward, and use a series of small scoots along the board", "Stand up and step onto the board", "Jump to the target surface"], correctIndex: 1, rationale: "Sliding board transfer: lock wheelchair, remove armrest, position board under buttock at angle to target surface, lean trunk forward, scoot along board in small movements, and remove board after seated. Requires sufficient UE strength.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2247", stem: "An OTA is treating a client with a pulmonary embolism who is on bedrest. What OT intervention is appropriate?", options: ["Aggressive ambulation", "Gentle bedside AROM of upper extremities, self-care activities within medical restrictions, and monitoring vital signs during activity", "No OT until off bedrest", "Resistive exercises immediately"], correctIndex: 1, rationale: "Pulmonary embolism bedrest OT: gentle UE AROM, simple self-care at bedside (grooming, feeding), monitor vital signs (HR, BP, O2 sat), watch for dyspnea/chest pain, and grade activity progression per physician orders.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2248", stem: "A client with a metacarpal fracture (boxer's fracture) is 6 weeks post-injury. What functional goal should the OTA prioritize?", options: ["Maximum wrist extension", "Restoring grip strength and functional hand use including fist closure for gripping, pinching, and performing daily activities", "Only finger extension", "Only thumb opposition"], correctIndex: 1, rationale: "Boxer's fracture (5th metacarpal neck) at 6 weeks: restore MCP flexion for full fist closure, grip strength, intrinsic muscle function, and functional hand use. Address any extensor lag and buddy tape during activities if needed.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2249", stem: "An OTA is working with a client who has agoraphobia. Which graded exposure approach is appropriate?", options: ["Immediate exposure to crowded places", "Start with anxiety-provoking situations ranked lowest on a fear hierarchy and gradually progress to more challenging situations with coping strategies", "Avoid all public places", "Only medication"], correctIndex: 1, rationale: "Agoraphobia graded exposure: create fear hierarchy (least to most anxiety-provoking), start with lowest item, practice coping strategies (breathing, grounding), systematic desensitization, and gradually progress as anxiety decreases.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2250", stem: "A client with a wrist ganglion cyst has pain during wrist extension. What conservative treatment does the OTA provide?", options: ["Rupture the cyst", "Wrist splinting for pain relief, activity modification to avoid positions of pain, and gentle ROM exercises to maintain wrist mobility", "Only ice application", "Immediate surgical referral"], correctIndex: 1, rationale: "Ganglion cyst conservative management: wrist splinting (reduces pain and cyst irritation), activity modification, gentle ROM, anti-inflammatory education, and monitor for changes. Many resolve spontaneously. Surgery if persistent and symptomatic.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2251", stem: "An OTA is treating a client with tardive dyskinesia who has difficulty with oral hygiene. Which adaptation is helpful?", options: ["Skip oral hygiene", "Use an electric toothbrush with a large handle for easier grasp, stabilize the head, and use a suction toothbrush if needed for safety", "Only use mouthwash", "Wait for involuntary movements to stop"], correctIndex: 1, rationale: "Tardive dyskinesia oral hygiene: electric toothbrush (reduces manual dexterity demand), large/built-up handle, head stabilization techniques, mirror for visual feedback, and suction toothbrush if aspiration risk from involuntary oral movements.", difficulty: 3, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2252", stem: "A client with a femoral neck fracture and hemiarthroplasty has posterior approach hip precautions. Which bathing technique is safe?", options: ["Sit on the tub floor", "Use a tub bench or shower chair, long-handled sponge for lower extremities, and avoid bending past 90° at the hip", "Step over the tub wall", "Squat in the shower"], correctIndex: 1, rationale: "Post-hemiarthroplasty posterior approach bathing: tub transfer bench or shower chair (avoid low seats), long-handled sponge (avoid hip flexion >90°), non-slip mat, grab bars, and handheld showerhead.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2253", stem: "An OTA is providing intervention for visual-perceptual deficits after a right CVA. Which deficit is MOST common?", options: ["Aphasia", "Left unilateral neglect — failure to attend to stimuli on the left side of space despite intact vision", "Right-sided weakness", "Dyslexia"], correctIndex: 1, rationale: "Right CVA perceptual deficits: left unilateral neglect (most common and functionally significant), spatial disorientation, constructional apraxia, body scheme disorders, and depth perception problems. Left CVA more commonly causes aphasia.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2254", stem: "A client with severe burns on both hands needs to maintain finger ROM. What exercise is performed multiple times daily?", options: ["Only wrist circles", "Composite finger flexion and extension, individual finger flexion, tendon gliding exercises, and thumb opposition performed every 1-2 hours while awake", "Only grip strengthening", "Only passive range of motion"], correctIndex: 1, rationale: "Burn hand ROM exercises: composite flexion/extension, isolated MCP/PIP/DIP flexion, tendon gliding sequence, thumb opposition/abduction, and web space stretching. Performed every 1-2 hours while awake to prevent contractures.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2255", stem: "An OTA is assessing the home environment for an older adult at risk for falls. Which area presents the GREATEST fall risk?", options: ["The kitchen", "The bathroom — wet surfaces, transfers in/out of tub, and lack of grab bars create the highest fall risk environment", "The bedroom", "The living room"], correctIndex: 1, rationale: "Bathroom is highest fall risk area for older adults: wet/slippery surfaces, transfers in/out of tub/shower, low toilet height, reaching for items, and lack of grab bars. Modifications: grab bars, non-slip mats, raised toilet seat, shower chair.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2256", stem: "A client with a recent amputation is demonstrating body image adjustment difficulties. Which OT activity helps promote positive body image?", options: ["Avoid mirrors", "Gradually increase exposure to residual limb through desensitization, mirror work, and engagement in valued occupations that rebuild self-identity", "Only discuss prosthetic options", "Ignore body image concerns"], correctIndex: 1, rationale: "Amputation body image: gradual exposure to residual limb (looking, touching), mirror work, desensitization, peer support from other amputees, engagement in valued occupations, identity rebuilding, and grief processing for limb loss.", difficulty: 2, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2257", stem: "An OTA is treating a client with myofascial pain syndrome. Which modality is MOST commonly used for trigger point treatment?", options: ["TENS only", "Trigger point release through sustained pressure, spray and stretch technique, dry needling referral, or ultrasound to the affected myofascial trigger points", "Only hot packs", "Only cryotherapy"], correctIndex: 1, rationale: "Myofascial trigger point treatment: sustained pressure/ischemic compression, spray and stretch (vapocoolant spray + stretch), deep tissue massage, ultrasound (thermal effect), and dry needling (physician/PT referral). OTA can perform manual release techniques.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2258", stem: "A client with a closed head injury is at Rancho Level V. What does this level indicate?", options: ["Comatose", "Confused-Inappropriate, non-purposeful — the client is alert and responds to simple commands but responses are random and non-purposeful", "Independent and goal-directed", "Automatic and appropriate"], correctIndex: 1, rationale: "Rancho Level V (Confused-Inappropriate): alert, responds to simple commands, but responses are non-purposeful. Agitated behavior decreased from Level IV. Cannot learn new information. Requires maximum assistance. Structure and consistency essential.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2259", stem: "An OTA is providing intervention for a child with sensory under-responsivity. Which activity provides intense proprioceptive input?", options: ["Light touch activities", "Wheelbarrow walking, jumping on a trampoline, carrying heavy objects, and wall push-ups — activities that provide deep pressure and joint compression", "Listening to quiet music", "Visual tracking activities"], correctIndex: 1, rationale: "Proprioceptive activities for under-responsive children: wheelbarrow walking, jumping, carrying heavy items, climbing, pushing/pulling, wall/chair push-ups, squeezing putty, and animal walks. These provide joint compression and muscle activation.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Sensory Processing" },
  { id: "ota-2260", stem: "A client with an extensor tendon repair in Zone III is at risk for which deformity?", options: ["Swan neck deformity", "Boutonniere deformity — central slip disruption at the PIP causes PIP flexion and DIP hyperextension", "Mallet finger", "Trigger finger"], correctIndex: 1, rationale: "Zone III extensor tendon injury (over PIP): central slip injury risks boutonniere deformity (PIP flexion, DIP hyperextension). Splint PIP in extension while allowing DIP flexion for lateral band gliding. Protect for 6-8 weeks.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2261", stem: "An OTA is treating a client with lymphedema of the upper extremity following mastectomy. What self-care education is essential?", options: ["Ignore swelling", "Avoid blood pressure measurements, blood draws, and cuts/burns on the affected arm; wear compression garments; and perform lymphatic drainage exercises", "Only elevate the arm", "Only wear tight clothing"], correctIndex: 1, rationale: "Post-mastectomy lymphedema precautions: no BP/blood draws/injections on affected arm, protect from cuts/burns, wear compression garment, perform manual lymph drainage self-massage, elevation, and exercise for lymphatic flow.", difficulty: 2, category: "Patient Education", topic: "Rehabilitation Principles" },
  { id: "ota-2262", stem: "A client with chronic stroke is 2 years post-onset. Can further functional gains be expected?", options: ["No gains possible after 6 months", "Yes — neuroplasticity continues beyond the acute recovery period, and intensive task-specific practice can lead to functional improvement even years after stroke", "Only with surgery", "Only with medication"], correctIndex: 1, rationale: "Chronic stroke neuroplasticity: research shows continued capacity for improvement years post-stroke through intensive, task-specific, repetitive practice. CIMT, task-oriented training, and high-dosage practice can drive cortical reorganization.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2263", stem: "An OTA is treating a client who had a median sternotomy for cardiac surgery. What precaution must be observed during ADLs?", options: ["No precautions", "Avoid pushing, pulling, or lifting more than 5-10 pounds and avoid shoulder flexion beyond 90° to protect the healing sternum for 6-8 weeks", "Full activity immediately", "Only avoid upper body exercise"], correctIndex: 1, rationale: "Sternal precautions post-cardiac surgery: no pushing/pulling/lifting >5-10 lbs for 6-8 weeks, avoid bilateral shoulder flexion >90°, log roll for bed mobility, pillow splinting for coughing, and modify ADLs to reduce sternal stress.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2264", stem: "A client with a congenital hand difference (absent thumb) needs adaptive equipment for school. What does the OTA recommend?", options: ["No adaptations needed", "Modified scissors, adapted writing grips, keyboarding alternatives, and functional grasp training using available digits with or without prosthetic thumb", "Standard school supplies only", "Only verbal accommodation"], correctIndex: 1, rationale: "Congenital hand difference school adaptations: modified scissors (loop or self-opening), adapted pencil grips, keyboard modifications, functional grasp training with available digits, prosthetic evaluation, and teacher education.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Assistive Devices" },
  { id: "ota-2265", stem: "An OTA is providing intervention for a client with somatoform disorder who presents with non-organic paralysis of the right arm. What approach is appropriate?", options: ["Confront the client about faking", "Focus on functional activities without directly challenging the symptom, address underlying psychological factors, and collaborate with the mental health team", "Only strength training", "Discharge from OT"], correctIndex: 1, rationale: "Somatoform/conversion disorder: avoid confrontation about symptom validity, focus on functional goals, graded activity exposure, stress management, address underlying psychological factors, and coordinate with psychiatry/psychology team.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2266", stem: "A client with osteoarthritis of the CMC joint of the thumb has pain with pinch activities. Which splint is indicated?", options: ["Full hand resting splint", "CMC stabilization splint (thumb post) that supports the thumb CMC joint while allowing finger function for daily activities", "Wrist cock-up only", "Buddy tape the thumb"], correctIndex: 1, rationale: "CMC OA thumb splint: CMC stabilization splint supports the thumb base joint, reduces pain, prevents further deformity, and allows functional hand use. May be hand-based or forearm-based depending on wrist involvement.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2267", stem: "An OTA is leading a cooking group for clients with intellectual disabilities. Which level of cueing is MOST appropriate to start with?", options: ["Full physical assistance", "Verbal cues with visual supports (picture recipe cards), allowing the client to attempt each step before providing additional cueing", "No cueing", "Only hand-over-hand assistance"], correctIndex: 1, rationale: "Cueing hierarchy for intellectual disability: start with least restrictive cue (verbal + visual supports), progress to gestural, modeling, partial physical, then full physical assistance only if needed. Fade cues as skills develop.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2268", stem: "A client with a third-degree burn on the anterior neck has which anti-deformity position?", options: ["Neck flexion", "Neck extension without a pillow to prevent flexion contracture from anterior scar formation", "Neck lateral flexion", "Neck rotation only"], correctIndex: 1, rationale: "Anterior neck burn: position in extension (no pillow, conforming splint, or neck extension collar). Scar contracture pulls neck into flexion, so extension is the anti-deformity position. Critical for preventing devastating contracture.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2269", stem: "An OTA is treating a client with chronic obstructive pulmonary disease who needs to shower independently. Which adaptation is MOST important?", options: ["Only cold water showers", "Use a shower chair, handheld showerhead, organize supplies within reach, and use pursed-lip breathing throughout the activity", "Short showers standing up", "Only sponge baths"], correctIndex: 1, rationale: "COPD shower adaptations: shower chair (eliminates standing fatigue), handheld showerhead, supplies organized within reach, pursed-lip breathing, rest breaks, bathroom exhaust fan on, and avoid excessive steam (may worsen dyspnea).", difficulty: 1, category: "Clinical Scenarios", topic: "ADL Training" },
  { id: "ota-2270", stem: "A client with autism spectrum disorder has restricted food preferences and will only eat 5 foods. What is the OTA's approach?", options: ["Force new foods", "Gradual systematic desensitization to new foods through sensory exploration, food chaining (linking accepted to similar new foods), and working with the interdisciplinary team", "Accept the restriction entirely", "Only nutritional supplements"], correctIndex: 1, rationale: "ASD food selectivity: gradual desensitization, food chaining (similar textures/flavors to accepted foods), sensory exploration (tolerate near, touch, smell, taste), SOS approach, and collaboration with SLP/dietitian/behavioral specialist.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Sensory Processing" },
  { id: "ota-2271", stem: "An OTA is providing wheelchair mobility training. What technique is used to navigate a curb cut when descending?", options: ["Wheelie over the curb", "Approach the curb cut straight on, lean slightly forward, and allow the front casters to descend first in a controlled manner", "Back down the curb cut", "Jump the wheelchair off the curb"], correctIndex: 1, rationale: "Wheelchair curb cut descent: approach straight on, lean slightly forward, front casters descend first, then rear wheels. Ascending: approach straight, push hard, front casters up first. For curbs without cuts, a wheelie technique is needed.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2272", stem: "A client with end-stage heart failure is referred to palliative OT. What is the PRIMARY focus of intervention?", options: ["Cardiac rehabilitation exercises", "Quality of life through meaningful occupation engagement, energy conservation, comfort, and support for the client and family during end-of-life", "Aggressive strengthening", "Return to work planning"], correctIndex: 1, rationale: "Palliative OT in end-stage heart failure: focus on quality of life, meaningful occupation engagement (what matters most), energy conservation, comfort positioning, caregiver training, legacy activities, and psychosocial support.", difficulty: 2, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2273", stem: "An OTA notices a colleague is practicing outside their scope of competency. What is the appropriate action?", options: ["Ignore it", "Report the concern through proper supervisory channels and follow the facility's protocol for addressing scope of practice violations", "Confront publicly", "Post about it on social media"], correctIndex: 1, rationale: "Scope of practice violation: report through proper channels (supervisor, compliance officer, ethics committee). Document concerns objectively. Follow facility protocol. May need to report to state licensing board if unresolved.", difficulty: 1, category: "Documentation", topic: "Rehabilitation Principles" },
  { id: "ota-2274", stem: "A client with a mallet finger is splinted. What position should the DIP be maintained in?", options: ["Flexion", "Full extension (0° or slight hyperextension) continuously for 6-8 weeks to allow healing of the terminal extensor tendon or avulsion fracture", "Neutral", "Variable positions throughout the day"], correctIndex: 1, rationale: "Mallet finger splinting: DIP in full extension (or slight hyperextension per physician) continuously for 6-8 weeks. If splint is removed and DIP drops into flexion, the 6-8 week period starts over. PIP should remain free.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2275", stem: "An OTA is treating a client with scleroderma affecting the face. Which exercise addresses oral aperture limitations?", options: ["No exercises help", "Oral stretching exercises, facial stretching, and mouth-opening exercises to maintain oral aperture for eating and dental hygiene", "Only apply heat", "Only manual stretching by the therapist"], correctIndex: 1, rationale: "Scleroderma facial involvement: oral stretching (wide mouth opening, lateral stretches), facial exercises (exaggerated expressions), massage, and sustained stretching to maintain oral aperture for eating, dental care, and expression.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2276", stem: "A client with a spinal cord injury at C6 level is being trained in tenodesis grasp. Why should the OTA NOT stretch the finger flexors?", options: ["Stretching is never harmful", "Maintaining finger flexor tightness is essential for tenodesis grasp — when the wrist extends, tight flexors passively close the fingers for functional grasp", "Stretching is painful", "Fingers are already flexible"], correctIndex: 1, rationale: "C6 SCI tenodesis: preservation of finger flexor tightness is critical. Wrist extension passively tensions tight flexors → finger flexion (grasp). If flexors are stretched/loose, the tenodesis mechanism is lost and functional grasp eliminated.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2277", stem: "An OTA is treating a client with a pilon fracture of the distal tibia. How does this affect OT treatment?", options: ["No impact on OT", "Affects weight-bearing status which impacts transfers, ADLs, and mobility training — OT must follow orthopedic weight-bearing restrictions during functional activities", "Only affects walking", "OT is not indicated"], correctIndex: 1, rationale: "Pilon fracture and OT: weight-bearing restrictions affect transfers (non-weight-bearing techniques), ADLs (modified bathing, dressing), mobility (wheelchair, walker), and home safety. OT addresses UE function and modified independence.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2278", stem: "A client with a cognitive deficit is unable to plan and sequence a multi-step task. This deficit is associated with damage to which brain region?", options: ["Occipital lobe", "Frontal lobe — executive functions including planning, sequencing, organization, and problem-solving are controlled by the prefrontal cortex", "Temporal lobe", "Cerebellum"], correctIndex: 1, rationale: "Executive function (planning, sequencing, organization, problem-solving, initiation, inhibition) is controlled by the prefrontal cortex (frontal lobe). Damage results in difficulty with multi-step tasks, goal-directed behavior, and self-monitoring.", difficulty: 2, category: "Anatomy & Physiology", topic: "Cognitive Rehab" },
  { id: "ota-2279", stem: "An OTA is providing education about joint protection to a client with juvenile idiopathic arthritis. Which principle is MOST important?", options: ["Use small joints for heavy tasks", "Use the strongest and largest joints available for tasks, distribute force over multiple joints, and avoid sustained gripping positions", "Grip tightly to strengthen joints", "Ignore joint pain during activities"], correctIndex: 1, rationale: "JIA joint protection: use largest/strongest joints, distribute force, avoid sustained positions, respect pain (stop before pain increases), use adaptive equipment, maintain ROM through play, and balance activity/rest.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2280", stem: "A client with a traumatic brain injury has impaired initiation. Which cueing strategy is MOST effective?", options: ["Wait for spontaneous initiation", "External cues such as alarms, checklists, verbal prompts, and environmental setup to trigger task initiation until internal initiation improves", "Only verbal reminders", "Physical assistance for all tasks"], correctIndex: 1, rationale: "TBI impaired initiation: external cues (alarms/timers, checklists, verbal prompts, environmental setup), establish routine, visual schedules, habit formation, and gradually fade external cues as internal initiation improves.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2281", stem: "An OTA is treating a client with De Quervain's tenosynovitis who is a new mother. Which activity modification is essential?", options: ["Avoid holding the baby", "Modify the lift technique to keep the wrist in neutral when lifting the baby, using the whole hand/forearm rather than thumb abduction", "Only use one hand", "Use a wrist brace at all times without exercise"], correctIndex: 1, rationale: "De Quervain's in new mothers: modify baby lifting (scoop under with forearm, neutral wrist, avoid thumb abduction), ergonomic breastfeeding positions, thumb spica splint, activity modification, and gentle stretching/tendon gliding.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2282", stem: "A client in ICU is intubated and sedated. What OT intervention is appropriate?", options: ["No OT in ICU", "Passive ROM, positioning to prevent contractures and skin breakdown, sensory stimulation, and splinting as needed", "Only documentation", "Active exercise programs"], correctIndex: 1, rationale: "ICU OT for intubated/sedated clients: PROM to maintain joint mobility, positioning (prevent contractures, pressure injuries), resting hand splints, sensory stimulation programs, and family education about positioning.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2283", stem: "An OTA is evaluating a child's bilateral integration skills. Which activity tests this ability?", options: ["Single-hand activities", "Cutting with scissors (stabilizing paper with one hand while cutting with the other) or catching a ball with both hands", "Visual tracking only", "Verbal reasoning tasks"], correctIndex: 1, rationale: "Bilateral integration assessment activities: cutting (stabilize/cut), stringing beads, tying shoes, buttoning, catching with two hands, clapping patterns, and jumping jacks. These require coordinated use of both body sides.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2284", stem: "A client with chronic kidney disease has a dialysis fistula in the left forearm. What precaution is critical during therapy?", options: ["Exercise the fistula arm vigorously", "Avoid blood pressure cuffs, restrictive clothing, and heavy resistance exercise on the fistula arm to protect the arteriovenous access", "Apply compression to the fistula", "No precautions needed"], correctIndex: 1, rationale: "Dialysis fistula precautions: no BP cuffs, tourniquets, or restrictive clothing on fistula arm, avoid heavy resistance exercise, protect from trauma, check for thrill/bruit, and report swelling/redness/loss of thrill.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2285", stem: "An OTA is providing low vision rehabilitation. What does the term 'eccentric viewing' mean?", options: ["Looking straight ahead", "Training the client to use peripheral retina to look slightly off-center from the object of interest to use undamaged areas of the retina for better vision", "Wearing prism glasses", "Closing one eye"], correctIndex: 1, rationale: "Eccentric viewing: technique for macular degeneration where central vision is lost. Client learns to look slightly off-center (above, below, or to the side) to use preserved peripheral retinal areas. Requires systematic training.", difficulty: 3, category: "Geriatric Rehabilitation", topic: "Assistive Devices" },
  { id: "ota-2286", stem: "A client with a cerebrovascular accident has pusher syndrome. What is the characteristic behavior?", options: ["Leaning away from the affected side", "Actively pushing toward the hemiplegic side with the intact extremities, resisting correction to midline", "Normal sitting balance", "Leaning forward only"], correctIndex: 1, rationale: "Pusher syndrome (contraversive pushing): client actively pushes toward hemiplegic side with intact extremities. Resists passive correction to midline. Different from typical lean toward uninvolved side. Treatment: visual feedback, weight-bearing to intact side.", difficulty: 4, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2287", stem: "An OTA is treating a client with a wrist TFCC (triangular fibrocartilage complex) injury. Which movement should be avoided?", options: ["Wrist flexion", "Forceful forearm rotation (pronation/supination) and ulnar deviation which stress the TFCC", "Finger flexion", "Shoulder motion"], correctIndex: 1, rationale: "TFCC injury precautions: avoid forceful pronation/supination, ulnar deviation, and loading in end-range rotation. Splint for support, gentle ROM within pain-free limits, and modify activities to minimize ulnar-sided wrist stress.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2288", stem: "A client with Williams syndrome demonstrates which characteristic behavior?", options: ["Social avoidance", "Overly friendly and sociable personality with excessive approach to strangers, combined with intellectual disability and visuospatial deficits", "Aggressive behavior", "Repetitive motor movements"], correctIndex: 1, rationale: "Williams syndrome: hypersociability (overly friendly, indiscriminate approach to strangers), intellectual disability, visuospatial deficits, relative language strength, cardiac issues (supravalvular aortic stenosis), and elfin facial features.", difficulty: 4, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2289", stem: "An OTA is providing adaptive equipment training for a client with quadriplegia at C5. Which device enables page turning?", options: ["Standard book holder", "Electric page turner operated by a switch, or a mouth stick for turning pages independently", "Regular bookmark", "No device exists"], correctIndex: 1, rationale: "C5 quadriplegia page turning: electric page turner (switch-operated), mouth stick, head pointer, or book holder with switch-adapted page turner. Selection depends on available motor function and client preference.", difficulty: 2, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2290", stem: "A client with a recent rotator cuff repair is wearing a shoulder immobilizer. What self-care activity can the OTA work on?", options: ["Bilateral overhead reaching", "One-handed techniques for grooming, feeding, and dressing while keeping the surgical arm in the immobilizer", "Full shoulder ROM exercises", "Lifting activities"], correctIndex: 1, rationale: "Rotator cuff repair in immobilizer: OT focuses on one-handed self-care techniques (grooming, feeding, dressing with affected arm in sling), energy conservation, and adapting tasks to maintain independence during recovery.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2291", stem: "An OTA is providing a therapeutic group for adolescents with eating disorders. What type of group is MOST appropriate?", options: ["Competitive cooking group", "Psychoeducational group focusing on body image, healthy coping skills, social skills, and media literacy", "Unstructured free time", "Weight-focused exercise group"], correctIndex: 1, rationale: "Adolescent eating disorder group: psychoeducational (body image, media literacy, healthy coping, assertiveness), process group (peer support, emotional expression), creative arts (self-expression), and life skills (meal planning, social eating).", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2292", stem: "A client with essential tremor has difficulty writing. Which adaptation is MOST helpful?", options: ["Thinner pens", "Weighted pen with a wide grip, stabilize the writing arm, and use cursive instead of print as it requires less stopping and starting", "Only typing", "Write with non-dominant hand"], correctIndex: 1, rationale: "Essential tremor writing adaptations: weighted pen, wide grip, arm stabilization, cursive (less stop/start), slant board, non-slip pad, and consider voice-to-text technology as alternative. Wrist weights may also help.", difficulty: 2, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2293", stem: "An OTA is treating a client with a healing fracture who is taking NSAIDs for pain. What should the OTA be aware of?", options: ["NSAIDs enhance bone healing", "Some evidence suggests NSAIDs may delay bone healing by inhibiting prostaglandins necessary for the inflammatory phase of fracture repair", "NSAIDs have no effect on bones", "NSAIDs always contraindicate therapy"], correctIndex: 1, rationale: "NSAIDs and fracture healing: evidence suggests potential delay in bone healing through prostaglandin inhibition (needed for inflammatory phase). Monitor healing progress, coordinate with physician, and be aware of this concern.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2294", stem: "A client with ALS is losing the ability to speak. What assistive technology should the OTA recommend early?", options: ["Wait until speech is completely gone", "Begin voice banking while the client can still speak clearly, and introduce augmentative and alternative communication (AAC) devices early", "Only pen and paper", "No technology available"], correctIndex: 1, rationale: "ALS speech decline: voice banking early (record client's voice for later use with AAC devices), introduce AAC devices while client can learn to use them, progress from low-tech (communication boards) to high-tech (eye-gaze systems) as function declines.", difficulty: 2, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2295", stem: "An OTA is treating a client with ulnar collateral ligament (UCL) reconstruction of the elbow (Tommy John surgery). What is the typical immobilization period?", options: ["No immobilization", "Posterior splint at 90° elbow flexion for approximately 7-10 days, then hinged brace with progressive ROM over 6 weeks", "Full extension cast for 12 weeks", "Sling only for 2 days"], correctIndex: 1, rationale: "UCL reconstruction rehab: posterior splint at 90° flexion initially, transition to hinged brace, progressive ROM (avoid valgus stress), gentle grip at 4-6 weeks, and full return to throwing at 12-18 months. OTA assists with ADLs during recovery.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2296", stem: "A client with delirium is confused and agitated during the OT session. What is the OTA's FIRST priority?", options: ["Complete the planned treatment", "Ensure safety, reorient the client, simplify communication, reduce environmental stimulation, and report the change in mental status to nursing/physician", "Restrain the client", "Discharge from OT"], correctIndex: 1, rationale: "Delirium management: ensure safety first, reorient (who, where, when), simplify communication, reduce stimulation, maintain calm environment, and immediately report change in mental status (delirium may indicate medical change).", difficulty: 1, category: "Patient Safety", topic: "Geriatric OT" },
  { id: "ota-2297", stem: "An OTA is providing intervention for a child with torticollis. Which stretching technique is used?", options: ["Forceful cervical manipulation", "Gentle passive stretching of the tight SCM by laterally flexing the head away from the affected side and rotating toward the affected side during play activities", "No stretching needed", "Only cervical collar"], correctIndex: 1, rationale: "Torticollis stretching: lateral flexion away from tight SCM (ear to opposite shoulder) and rotation toward the affected side (chin to affected shoulder). Incorporate into play, tummy time, and positioning throughout the day.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2298", stem: "A client with a new colostomy is having difficulty with clothing choices. What recommendation does the OTA provide?", options: ["Only hospital gowns", "Loose-fitting clothing, patterns that camouflage the pouch, high-waisted pants/skirts, and one-piece swimsuits or tankinis", "Only sweatpants", "No clothing adaptations exist"], correctIndex: 1, rationale: "Colostomy clothing adaptations: loose-fitting clothes over pouch area, patterns/prints camouflage pouch outline, high-waisted bottoms, suspenders instead of tight belts, one-piece swimsuits, and stoma guard for activities.", difficulty: 1, category: "Patient Education", topic: "ADL Training" },
  { id: "ota-2299", stem: "An OTA is assessing a client's functional reach. What is the normal functional reach distance in standing?", options: ["3-5 inches", "Approximately 10-13 inches for healthy adults, with less than 6 inches indicating increased fall risk", "20-25 inches", "1-2 inches"], correctIndex: 1, rationale: "Functional Reach Test: average 10-13 inches for healthy adults. Less than 10 inches = moderate fall risk. Less than 6 inches = high fall risk. Simple clinical measure of balance and dynamic stability limits.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2300", stem: "A client with Ehlers-Danlos syndrome (hypermobility type) has chronic joint instability. What OT principle is essential?", options: ["Aggressive stretching", "Joint stabilization through strengthening, proprioceptive training, activity modification, and protective splinting without overstretching hypermobile joints", "Maximum flexibility training", "Ignore joint instability"], correctIndex: 1, rationale: "EDS hypermobility OT: strengthening (joint stabilization, not stretching), proprioceptive training, joint protection, supportive splinting (stabilize without restricting function), activity modification, pain management, and energy conservation.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2301", stem: "An OTA is treating a client who is homeless and has a mental illness. What social determinant of health is the PRIMARY barrier to OT outcomes?", options: ["Age", "Lack of stable housing — housing instability undermines all other aspects of health, safety, routine, medication compliance, and occupation", "Gender", "Education level"], correctIndex: 1, rationale: "Homelessness as social determinant: affects medication compliance, wound care, nutrition, sleep, safety, hygiene, routine establishment, and therapy attendance. Housing-first approach: stable housing is foundational for all other interventions.", difficulty: 2, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2302", stem: "A client with a severe traumatic brain injury has central fever. What does this indicate?", options: ["Common cold", "Hypothalamic dysfunction causing temperature dysregulation that is not infection-related and requires monitoring during therapy", "Wound infection", "Normal finding"], correctIndex: 1, rationale: "Central fever post-TBI: hypothalamic dysfunction causes temperature dysregulation without infectious cause. Common in severe TBI. Monitor temperature during therapy, use cooling strategies, and differentiate from infection-related fever.", difficulty: 4, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
];
